-- create "orders" table
CREATE TABLE "orders" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "status" smallint NOT NULL DEFAULT 0, "payment_status" smallint NOT NULL DEFAULT 0, "fulfillment_status" smallint NOT NULL DEFAULT 0, "currency" character varying(3) NOT NULL, "total_amount" bigint NOT NULL, "shipping_address" jsonb NOT NULL, "cancelled_at" timestamptz NULL, "shop_id" bigint NOT NULL, "member_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "orders_members_member" FOREIGN KEY ("member_id") REFERENCES "members" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "orders_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "orders_fulfillment_status_check" CHECK (fulfillment_status >= 0), CONSTRAINT "orders_payment_status_check" CHECK (payment_status >= 0), CONSTRAINT "orders_status_check" CHECK (status = ANY (ARRAY[0, 1])), CONSTRAINT "orders_total_amount_check" CHECK (total_amount >= 0));
-- create index "order_shop_id_member_id" to table: "orders"
CREATE INDEX "order_shop_id_member_id" ON "orders" ("shop_id", "member_id");
-- create index "order_shop_id_status" to table: "orders"
CREATE INDEX "order_shop_id_status" ON "orders" ("shop_id", "status");
-- create "order_items" table
CREATE TABLE "order_items" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "product_id" bigint NULL, "product_title" character varying(200) NOT NULL, "sku_id" bigint NULL, "sku_code" character varying(64) NOT NULL, "quantity" integer NOT NULL, "price_amount" bigint NOT NULL, "currency" character varying(3) NOT NULL, "order_id" bigint NOT NULL, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "order_items_orders_items" FOREIGN KEY ("order_id") REFERENCES "orders" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "order_items_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "order_items_price_amount_check" CHECK (price_amount >= 0), CONSTRAINT "order_items_quantity_check" CHECK (quantity > 0));
-- create index "orderitem_order_id" to table: "order_items"
CREATE INDEX "orderitem_order_id" ON "order_items" ("order_id");
-- create index "orderitem_shop_id" to table: "order_items"
CREATE INDEX "orderitem_shop_id" ON "order_items" ("shop_id");
